import React, { useState, useEffect, useMemo } from "react";
import { Layout, Row, Col, Card, Table, Tag, Input, Button, List, Typography, message, Modal, Space } from "antd";
import { SearchOutlined, CaretUpOutlined, CaretDownOutlined, CaretLeftOutlined, CaretRightOutlined, StopOutlined, AimOutlined, PlayCircleOutlined } from "@ant-design/icons";
import ReactECharts from "echarts-for-react";
import { MapContainer, TileLayer, Marker, Popup, useMap, useMapEvents, Polyline } from "react-leaflet";
import L from "leaflet";
import { useI18n } from "@/framework/i18n/hooks";
import { useTheme } from "@/framework/theme/ThemeProvider";
import { themeTokens } from "@/framework/theme/themes";
import { mockRobots as initialMockRobots, mockLogs, chartData } from "../../mockup/dashboardData";

// Fix leaflet icon issue in Vite/Webpack
import markerIcon from "leaflet/dist/images/marker-icon.png";
import markerShadow from "leaflet/dist/images/marker-shadow.png";

const DefaultIcon = L.icon({
  iconUrl: markerIcon,
  shadowUrl: markerShadow,
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});
L.Marker.prototype.options.icon = DefaultIcon;

const { Title, Text } = Typography;

// 로봇 상태별 마커 생성 함수
const createRobotIcon = (status: string, isDark: boolean, isSelected: boolean) => {
  const color = status === 'online' ? '#22c55e' : (status === 'warning' ? '#f59e0b' : '#ef4444');
  const size = isSelected ? 48 : 38;
  const shadow = isSelected ? `0 0 20px ${color}, inset 0 0 8px ${color}` : `0 0 10px ${color}`;
  
  return L.divIcon({
    className: 'custom-robot-icon',
    html: `
      <div style="width: ${size}px; height: ${size}px; background-color: rgba(255,255,255,0.05); backdrop-filter: blur(4px); border: 2px solid ${color}; border-radius: 8px; box-shadow: ${shadow}; transition: all 0.3s ease; display: flex; align-items: center; justify-content: center; position: relative; overflow: hidden;">
        <img src="${import.meta.env.BASE_URL}assets/platforms/autonomous-driving/robot-icon.png" style="width: 85%; height: 85%; object-fit: contain;" />
        ${isSelected ? `<div style="position: absolute; top: -3px; right: -3px; width: 12px; height: 12px; background: var(--ms-color-primary); border-radius: 50%; border: 2px solid #fff;"></div>` : ''}
      </div>`,
    iconSize: [size, size],
    iconAnchor: [size/2, size/2],
  });
};

// 목적지 깃발 아이콘 생성 함수
const createFlagIcon = () => {
    return L.divIcon({
      className: 'custom-flag-icon',
      html: `
        <div style="position: relative; width: 30px; height: 30px;">
          <svg width="30" height="30" viewBox="0 0 24 24" fill="none" stroke="var(--ms-color-primary)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M4 15s1-1 4-1 5 2 8 2 4-1 4-1V3s-1 1-4 1-5-2-8-2-4 1-4 1z"></path>
            <line x1="4" y1="22" x2="4" y2="15"></line>
          </svg>
        </div>`,
      iconSize: [30, 30],
      iconAnchor: [4, 30],
    });
};

// 지도 클릭/우클릭 이벤트 처리 컴포넌트
function MapEventHandler({ onMapClick, onRightClick }: { onMapClick: (lat: number, lng: number) => void, onRightClick: (lat: number, lng: number) => void }) {
  useMapEvents({
    click: (e) => onMapClick(e.latlng.lat, e.latlng.lng),
    contextmenu: (e) => onRightClick(e.latlng.lat, e.latlng.lng)
  });
  return null;
}

// 장소 검색 후 지도를 이동시키는 컴포넌트
function MapSearchHandler({ center }: { center: [number, number] | null }) {
  const map = useMap();
  useEffect(() => {
    if (center) {
      map.setView(center, 16, { animate: true });
    }
  }, [center, map]);
  return null;
}

export default function AutonomousDrivingDashboard() {
  const { t } = useI18n(["autonomous-driving"]);
  const { theme } = useTheme();
  const isDark = themeTokens[theme]?.meta?.group === "dark";

  const [selectedRobotId, setSelectedRobotId] = useState<string | null>(null);
  const [tempDest, setTempDest] = useState<[number, number] | null>(null);
  const [isAssigning, setIsAssigning] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [mapCenter, setMapCenter] = useState<[number, number]>([35.1920, 129.0600]);
  const [robots, setRobots] = useState(initialMockRobots.map(r => ({
      ...r,
      lat: 35.1920 + (Math.random() - 0.5) * 0.005,
      lng: 129.0600 + (Math.random() - 0.5) * 0.005
  })));
  const [searching, setSearching] = useState(false);

  // 마커 인스턴스 참조 저장
  const markerRefs = React.useRef<Record<string, L.Marker | null>>({});

  useEffect(() => {
    if (selectedRobotId && markerRefs.current[selectedRobotId]) {
      markerRefs.current[selectedRobotId]?.openPopup();
    }
  }, [selectedRobotId]);

  // 로봇 이동 시뮬레이션
  useEffect(() => {
    const timer = setInterval(() => {
      setRobots(prev => prev.map(r => ({
        ...r,
        lat: r.lat + (Math.random() - 0.5) * 0.0001,
        lng: r.lng + (Math.random() - 0.5) * 0.0001
      })));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const handleSearch = async () => {
    if (!searchQuery) return;
    setSearching(true);
    try {
      const response = await fetch(
        `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(searchQuery)}`
      );
      const data = await response.json();
      if (data && data.length > 0) {
        const { lat, lon } = data[0];
        const target: [number, number] = [parseFloat(lat), parseFloat(lon)];
        setMapCenter(target);
        message.success(t("dashboard.locFound", { name: data[0].display_name }));
      } else {
        message.warning(t("dashboard.noLoc"));
      }
    } catch (error) {
      message.error(t("dashboard.apiErr"));
    } finally {
      setSearching(false);
    }
  };

  const handleSetDestination = () => {
      if (!selectedRobotId) {
          message.warning(t("dashboard.selectToControl") || "Please select a robot first.");
          return;
      }
      if (!tempDest) return;

      setRobots(prev => prev.map(r => 
          r.id === selectedRobotId 
          ? { ...r, destLat: tempDest[0], destLng: tempDest[1] } 
          : r
      ));
      setTempDest(null);
      message.success(`New destination assigned to ${selectedRobotId}`);
  };

  // 선택된 로봇 데이터
  const selectedRobot = useMemo(() => robots.find(r => r.id === selectedRobotId), [selectedRobotId, robots]);

  // 선택된 로봇에 따른 차트 데이터 시뮬레이션
  const chartOptions = useMemo(() => {
    const isSingle = !!selectedRobotId;
    return {
      backgroundColor: 'transparent',
      title: { 
        text: isSingle ? `${selectedRobotId} Metric` : 'System Aggregate',
        textStyle: { color: 'var(--ms-color-text)', fontSize: 13, fontWeight: 500 },
        left: 'center', top: 5
      },
      tooltip: { trigger: 'axis' },
      legend: { textStyle: { color: 'var(--ms-color-muted)' }, data: ['NPU FPS', 'Velocity'], bottom: 0 },
      grid: { left: '3%', right: '4%', bottom: '15%', top: '20%', containLabel: true },
      xAxis: { type: 'category', boundaryGap: false, data: chartData.labels, axisLine: { lineStyle: { color: 'var(--ms-border-color)' } } },
      yAxis: { type: 'value', axisLine: { lineStyle: { color: 'var(--ms-border-color)' } }, splitLine: { lineStyle: { color: 'rgba(255,255,255,0.05)' } } },
      series: [
        { name: 'NPU FPS', type: 'line', data: isSingle ? chartData.fps.map(v => v + (Math.random()*10 - 5)) : chartData.fps, smooth: true, lineStyle: { color: 'var(--ms-color-primary)' } },
        { name: 'Velocity', type: 'line', data: isSingle ? chartData.velocity.map(v => v + (Math.random()*2 - 1)) : chartData.velocity, smooth: true, lineStyle: { color: '#eab308' } },
      ]
    };
  }, [selectedRobotId]);

  // 필터링된 로그
  const filteredLogs = useMemo(() => {
    if (!selectedRobotId) return mockLogs;
    return mockLogs.filter(log => log.id === selectedRobotId);
  }, [selectedRobotId]);

  const columns = [
    { title: 'ID', dataIndex: 'id', key: 'id', render: (text: string) => <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}><Avatar size="small" src={`${import.meta.env.BASE_URL}assets/platforms/autonomous-driving/robot-icon.png`} /> <span style={{ color: "var(--ms-color-text)" }}>{text}</span></div> },
    { title: t("dashboard.status"), dataIndex: 'status', key: 'status', render: (status: string) => <div style={{ width: 40, height: 16, borderRadius: 8, background: status === 'online' ? '#22c55e' : (status === 'warning' ? '#f59e0b' : '#64748b'), opacity: 0.6 }} /> },
    { title: t("dashboard.battery"), dataIndex: 'battery', key: 'battery', render: (val: number) => <span style={{ color: val < 60 ? '#ef4444' : 'var(--ms-color-text)' }}>{val}%</span> },
    { title: t("dashboard.temp"), dataIndex: 'temp', key: 'temp', render: (val: number) => <span style={{ color: "var(--ms-color-text)" }}>{val}°C</span> },
  ];

  // 테마에 따른 OSM 타일 URL 선택
  const tileUrl = isDark 
    ? "https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png"
    : "https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png";

  return (
    <div style={{ padding: 0, height: "calc(100vh - 64px)", overflow: "hidden", background: "var(--ms-color-bg-layout)" }}>
      <Row gutter={[0, 0]} style={{ height: "100%" }}>
        {/* Left: Map Area */}
        <Col xs={24} lg={14} style={{ height: "100%" }}>
          <div style={{ height: "100%", position: "relative" }}>
            <MapContainer 
                center={mapCenter} 
                zoom={16} 
                style={{ height: "100%", width: "100%", cursor: isAssigning ? "crosshair" : "grab" }}
                zoomControl={false}
            >
              <TileLayer
                attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>'
                url={tileUrl}
              />
              <MapEventHandler 
                onMapClick={(lat, lng) => { 
                    if (isAssigning && selectedRobotId) {
                        setRobots(prev => prev.map(r => r.id === selectedRobotId ? { ...r, destLat: lat, destLng: lng } : r));
                        setIsAssigning(false);
                        message.success(`New destination assigned to ${selectedRobotId}`);
                    } else {
                        setSelectedRobotId(null); 
                        setTempDest(null); 
                        setIsAssigning(false);
                    }
                }} 
                onRightClick={(lat, lng) => setTempDest([lat, lng])} 
              />
              <MapSearchHandler center={mapCenter} />
              
              {/* 우클릭 시 생성되는 임시 목적지 팝업 */}
              {tempDest && (
                  <Popup 
                    position={tempDest} 
                    eventHandlers={{
                        remove: () => setTempDest(null)
                    }}
                  >
                      <div style={{ color: "#000", padding: "4px", minWidth: 140 }}>
                          <div style={{ fontWeight: 700, marginBottom: 8 }}>Target Location</div>
                          <div style={{ marginBottom: 12, fontSize: 11 }}>{tempDest[0].toFixed(5)}, {tempDest[1].toFixed(5)}</div>
                          <Button 
                              type="primary" 
                              size="small" 
                              block 
                              icon={<AimOutlined />} 
                              onClick={handleSetDestination}
                              disabled={!selectedRobotId}
                          >
                              {selectedRobotId ? `Assign to ${selectedRobotId}` : "Select a robot first"}
                          </Button>
                      </div>
                  </Popup>
              )}
              
              {/* 목적지 선 및 깃발 */}
              {selectedRobot && selectedRobot.destLat && (
                  <>
                    <Polyline 
                        positions={[[selectedRobot.lat, selectedRobot.lng], [selectedRobot.destLat, selectedRobot.destLng]]}
                        pathOptions={{ color: 'var(--ms-color-primary)', weight: 2, dashArray: '8, 8', opacity: 0.6 }}
                    />
                    <Marker position={[selectedRobot.destLat, selectedRobot.destLng]} icon={createFlagIcon()}>
                        <Popup>
                            <div style={{ fontSize: 11, color: "#000" }}>
                                <strong>Destination</strong><br/>
                                {selectedRobot.mission}
                            </div>
                        </Popup>
                    </Marker>
                  </>
              )}

              {robots.map(robot => (
                <Marker 
                    ref={(el) => { markerRefs.current[robot.id] = el; }}
                    key={robot.id} 
                    position={[robot.lat, robot.lng]} 
                    icon={createRobotIcon(robot.status, isDark, selectedRobotId === robot.id)}
                    eventHandlers={{
                        click: (e) => {
                            setSelectedRobotId(robot.id);
                            L.DomEvent.stopPropagation(e);
                        }
                    }}
                >
                  <Popup>
                    <div style={{ color: "#000", padding: "4px" }}>
                        <div style={{ fontWeight: "800", borderBottom: "1px solid #eee", marginBottom: 4 }}>{robot.id}</div>
                        <div style={{ fontSize: 11 }}>{t("dashboard.status")}: <span style={{ color: robot.status === 'online' ? '#22c55e' : '#f59e0b' }}>{robot.status}</span></div>
                        <div style={{ fontSize: 11 }}>{t("dashboard.battery")}: {robot.battery}%</div>
                        <div style={{ fontSize: 11 }}>Mission: {robot.mission}</div>
                    </div>
                  </Popup>
                </Marker>
              ))}
            </MapContainer>
            
            {/* Overlay Search */}
            <div style={{ position: "absolute", top: 20, left: 20, zIndex: 1000, width: 340 }}>
                <Input.Search 
                    placeholder={t("dashboard.searchPlaceholder")}
                    allowClear
                    enterButton={searching ? "..." : "Search"}
                    onSearch={handleSearch}
                    onChange={e => setSearchQuery(e.target.value)}
                    style={{ background: "rgba(var(--ms-color-bg-container-rgb), 0.85)", border: "1px solid var(--ms-border-color)", borderRadius: 8, backdropFilter: "blur(10px)", color: "var(--ms-color-text)" }} 
                />
            </div>

            {/* Map Legend */}
            <div style={{ position: "absolute", bottom: 20, left: 20, zIndex: 1000, padding: 12, background: "rgba(var(--ms-color-bg-container-rgb), 0.9)", borderRadius: 8, border: "1px solid var(--ms-border-color)", backdropFilter: "blur(4px)" }}>
                <div style={{ fontSize: 12, fontWeight: 700, marginBottom: 8, color: "var(--ms-color-text)" }}>{t("dashboard.legend")}</div>
                <div style={{ display: 'flex', gap: 12, fontSize: 11, color: "var(--ms-color-muted)" }}>
                    <span><span style={{ color: "#22c55e" }}>●</span> {t("dashboard.online")}</span>
                    <span><span style={{ color: "#f59e0b" }}>●</span> {t("dashboard.warning")}</span>
                    <span><span style={{ color: "#ef4444" }}>●</span> {t("dashboard.offline")}</span>
                </div>
            </div>
          </div>
        </Col>

        {/* Right Area: Tables, Logs, Controls */}
        <Col xs={24} lg={10} style={{ height: "100%", overflowY: "auto", background: "var(--ms-color-bg-container)", borderLeft: "1px solid var(--ms-border-color)" }}>
          <div style={{ padding: 20, display: "flex", flexDirection: "column", gap: 20 }}>
            <Card
              title={<Title level={5} style={{ margin: 0, color: "var(--ms-color-text)" }}>{t("dashboard.tableTitle")}</Title>}
              variant="borderless"
              style={{ background: "rgba(255,255,255,0.03)", border: "1px solid var(--ms-border-color)" }}
              styles={{ body: { padding: 0 } }}
            >
              <Table 
                dataSource={robots} 
                columns={columns} 
                pagination={false} 
                size="small" 
                scroll={{ y: 250 }} 
                rowKey="id"
                rowClassName={(record) => record.id === selectedRobotId ? "ms-table-row-selected" : ""}
                onRow={(record) => ({
                    onClick: () => {
                        setSelectedRobotId(record.id);
                        setMapCenter([record.lat, record.lng]);
                    }
                })}
              />
            </Card>

            <Card
              title={<Title level={5} style={{ margin: 0, color: "var(--ms-color-text)", fontSize: 14 }}>{t("dashboard.logsTitle")} {selectedRobotId ? `(${selectedRobotId})` : "(All)"}</Title>}
              variant="borderless"
              style={{ background: "rgba(255,255,255,0.03)", border: "1px solid var(--ms-border-color)", height: 220 }}
              styles={{ body: { padding: 12, height: "calc(100% - 46px)", overflowY: "auto" } }}
            >
                <div style={{ fontFamily: "monospace", fontSize: 12, color: "var(--ms-color-muted)" }}>
                    {filteredLogs.map((log, i) => (
                        <div key={i} style={{ marginBottom: 4, opacity: selectedRobotId ? 1 : 0.8 }}>
                            [{log.time}] [<span style={{ color: "var(--ms-color-primary)" }}>{log.id}</span>] {log.message}
                        </div>
                    ))}
                    {filteredLogs.length === 0 && <div style={{ textAlign: "center", padding: 20 }}>No logs found for this unit.</div>}
                </div>
            </Card>

            <Card
                title={<Title level={5} style={{ margin: 0, color: "var(--ms-color-text)", fontSize: 14 }}>{t("dashboard.remoteTitle")} {selectedRobotId ? `- ${selectedRobotId}` : ""}</Title>}
                variant="borderless"
                style={{ background: "rgba(255,255,255,0.03)", border: "1px solid var(--ms-border-color)" }}
                styles={{ body: { padding: "16px 20px" } }}
            >
                <div style={{ pointerEvents: selectedRobotId ? "auto" : "none", display: "flex", flexDirection: "row", alignItems: "center", justifyContent: "space-between", gap: 24, width: "100%" }}>
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 40px)", gap: 6, flexShrink: 0 }}>
                        <div />
                        <Button disabled={!selectedRobotId} icon={<CaretUpOutlined />} style={{ width: 40, height: 40 }} />
                        <div />
                        <Button disabled={!selectedRobotId} icon={<CaretLeftOutlined />} style={{ width: 40, height: 40 }} />
                        <div />
                        <Button disabled={!selectedRobotId} icon={<CaretRightOutlined />} style={{ width: 40, height: 40 }} />
                        <div />
                        <Button disabled={!selectedRobotId} icon={<CaretDownOutlined />} style={{ width: 40, height: 40 }} />
                        <div />
                    </div>
                    <div style={{ flex: 1, display: "flex", flexDirection: "column", gap: 12 }}>
                        <Button 
                            disabled={!selectedRobotId}
                            type={isAssigning ? "primary" : "default"}
                            style={{ height: 50, width: "100%", fontWeight: isAssigning ? 700 : 400 }}
                            onClick={(e) => { 
                                e.stopPropagation(); 
                                if (!isAssigning) message.info(t("dashboard.rightClickGuide") || "Click anywhere on the map to set a waypoint.");
                                setIsAssigning(!isAssigning); 
                            }}
                        >
                            {isAssigning ? "Selecting..." : t("dashboard.waypoint")}
                        </Button>
                        <div style={{ display: "flex", gap: 8 }}>
                            <Button disabled={!selectedRobotId} danger type="primary" icon={<StopOutlined />} style={{ height: 50, flex: 1, fontWeight: 700 }}>{t("dashboard.stop")}</Button>
                            <Button disabled={!selectedRobotId} type="primary" icon={<PlayCircleOutlined />} style={{ height: 50, flex: 1, fontWeight: 700, background: !selectedRobotId ? undefined : "#10b981", borderColor: !selectedRobotId ? undefined : "#10b981" }}>{t("dashboard.resume")}</Button>
                        </div>
                    </div>
                </div>
            </Card>

            <Card
                    title={<Title level={5} style={{ margin: 0, color: "var(--ms-color-text)", fontSize: 14 }}>{t("dashboard.performance")}</Title>}
                    variant="borderless"
                    style={{ background: "rgba(255,255,255,0.03)", border: "1px solid var(--ms-border-color)" }}
                    styles={{ body: { padding: "10px 0" } }}
            >
                <ReactECharts option={chartOptions} style={{ height: 200, width: "100%" }} />
            </Card>
          </div>
        </Col>
      </Row>
      <style>{`
        .ant-table { background: transparent !important; }
        .ant-table-thead > tr > th { background: rgba(255,255,255,0.05) !important; color: var(--ms-color-muted) !important; border-bottom: 1px solid var(--ms-border-color) !important; }
        .ant-table-tbody > tr > td { border-bottom: 1px solid rgba(255,255,255,0.02) !important; cursor: pointer; transition: all 0.2s ease; }
        .ant-table-tbody > tr:hover > td { background: rgba(255,255,255,0.05) !important; }
        
        /* 선택된 행 강조 스타일 강화 */
        .ms-table-row-selected td { 
            background: linear-gradient(90deg, rgba(24, 144, 255, 0.25) 0%, rgba(24, 144, 255, 0.05) 100%) !important; 
            color: var(--ms-color-primary) !important; 
            font-weight: 700 !important;
            border-bottom: 1px solid rgba(24, 144, 255, 0.3) !important;
            position: relative;
        }
        .ms-table-row-selected td:first-child {
            border-left: 4px solid var(--ms-color-primary) !important;
            padding-left: 12px !important;
        }
        .ms-table-row-selected span, .ms-table-row-selected div {
            color: var(--ms-color-primary) !important;
        }

        .custom-robot-icon { pointer-events: auto !important; }
      `}</style>
    </div>
  );
}

const Avatar = ({ size, src }: { size: string, src: string }) => (
    <div style={{ width: size === 'small' ? 20 : 32, height: size === 'small' ? 20 : 32, borderRadius: "50%", background: "var(--ms-border-color)", overflow: "hidden" }}>
        <img src={src} alt="avatar" style={{ width: "100%", height: "100%", objectFit: "contain" }} />
    </div>
);
